class UpdateUserProfileInput(graphene.InputObjectType):
    username = graphene.String(required=False)
    email = graphene.String(required=False)
    bio = graphene.String(required=False)
    role = graphene.String(required=False)
    is_admin = graphene.Boolean(required=False)
    credits = graphene.Int(required=False)
    subscription_tier = graphene.String(required=False)

class UpdateUserProfileMutation(Mutation):
    class Arguments:
        input_ = UpdateUserProfileInput(required=True)

    Output = User

    def mutate(self, info, input_):
        authenticated_user = info.context.get('user')
        if not authenticated_user:
            raise Exception("Authentication required")

        # Update user profile logic here
        for key, value in input_.items():
            if value is not None:
                setattr(authenticated_user, key, value)

        return User(**{field.name: getattr(authenticated_user, field.name) for field in User._meta.fields})

